import { Link } from "react-router-dom";
import authService from "src/auth/auth.service";
import { epochTogmt } from "src/utils/Common";

export const tableProductConstant = (handleConfirmModal) => {
    return [
        {
            id: 1,
            name: "Product name",
            cell: (row) => {
                return (
                    <Link to={`/product/edit/${row?.id}`}>
                        <span className="sub">{row.name}</span>
                    </Link>
                );
            },
            sortable: true,
            reorder: true,
            style: {
                color: "#202124",
                fontSize: "14px",
                fontWeight: 500,
            },
        },

        {
            id: 2,
            name: "Description",
            selector: (row) => row.description
        },
        {
            id: 2,
            name: "Create Time",
            selector: (row) =>row.createTime &&  epochTogmt(row.createTime)
        },
        {
            id: 4,
            name: "Delete",
            cell: (row) => {
                return <i className={"fa-regular fa-trash-can" + (row.status === "ENABLE" || !authService.getPermission("DELETE") ? " disable" : "")} onClick={(e) => { handleConfirmModal(row?.id) }}></i>;
            },
            sortable: true,
            reorder: true,
        },
    ];
};
